function sanitizeTg(s) {
  return String(s || '').replace(/[_*`\[\]]/g, ' ');
}

function clip(s, n) {
  const t = String(s || '').replace(/\s+/g, ' ').trim();
  if (t.length <= n) return t;
  return t.slice(0, n - 1) + '…';
}

function kw(v) {
  if (Array.isArray(v)) return v.filter(Boolean).join(', ');
  if (v == null) return '';
  return String(v);
}

function fmtCatBlock(c, idx) {
  if (!c || typeof c !== 'object') return [];
  const id = c.category_id ?? '—';
  const head = `${idx}. id=${id} | ${clip(c.category_name || '', 90)}`;
  const meta = [
    c.category_code ? `code=${c.category_code}` : null,
    c.direction ? `dir=${c.direction}` : null,
    c.hierarchy_level ? `lvl=${c.hierarchy_level}` : null,
    c.product_type ? `type=${c.product_type}` : null,
    c.administration_route ? `route=${c.administration_route}` : null,
    c.age_segment ? `age=${c.age_segment}` : null,
    c.mnn_cluster ? `mnn=${c.mnn_cluster}` : null,
    c.need_nosology ? `nosology=${c.need_nosology}` : null,
  ].filter(Boolean).join(' | ');
  const lines = [head];
  if (meta) lines.push(`   ${clip(meta, 220)}`);
  if (c.inclusion_comment) lines.push(`   описание: ${clip(c.inclusion_comment, 280)}`);
  if (c.notes) lines.push(`   notes: ${clip(c.notes, 160)}`);
  const inc = kw(c.include_keywords);
  const exc = kw(c.exclude_keywords);
  if (inc) lines.push(`   include: ${clip(inc, 140)}`);
  if (exc) lines.push(`   exclude: ${clip(exc, 100)}`);
  return lines;
}

function fmtProp(label, p, byId) {
  if (!p || typeof p !== 'object') return null;
  const cid = p.category_id != null ? Number(p.category_id) : null;
  const cat = (cid != null && byId[cid]) ? byId[cid] : null;
  const parts = [];
  if (p.category_id != null) parts.push(`cat=${p.category_id}`);
  if (cat?.category_name) parts.push(clip(cat.category_name, 60));
  if (p.direction) parts.push(`dir=${p.direction}`);
  if (p.block_family) parts.push(`block=${p.block_family}`);
  if (p.confidence != null) parts.push(`conf=${p.confidence}`);
  if (p.winner_source) parts.push(`winner=${p.winner_source}`);
  if (p.explanation) parts.push(clip(p.explanation, 140));
  if (!parts.length) return null;
  return `• ${label}: ${parts.join(' | ')}`;
}

const settingsChat = String($('HR — Load Settings').first().json.chat_id || '').trim();

return items.map((item) => {
  const row = item.json;
  const payload = typeof row.payload === 'string' ? JSON.parse(row.payload) : (row.payload || {});
  const qid = Number(row.id);
  const chatId = String(row.telegram_chat_id || settingsChat || '').trim();
  const shortlist = Array.isArray(payload.shortlist_top) ? payload.shortlist_top : [];
  const proposals = payload.proposals || {};
  const suggested = payload.suggested_category || (
    payload.suggested_category_id != null
      ? { category_id: payload.suggested_category_id }
      : null
  );

  const byId = {};
  for (const c of shortlist) {
    const id = Number(c.category_id);
    if (Number.isFinite(id)) byId[id] = c;
  }
  if (suggested && suggested.category_id != null) {
    byId[Number(suggested.category_id)] = { ...byId[Number(suggested.category_id)], ...suggested };
  }

  const lines = [
    `Review #${qid} · product ${payload.product_id}`,
    `run_id=${payload.run_id || row.run_id || '—'}`,
    '',
    clip(payload.product_name || payload.combined_text || '—', 300),
    '',
    'Предложения модели:',
  ];

  for (const label of ['judge', 'fallback_2b', 'primary_llm', 'fallback_2a']) {
    const line = fmtProp(label, proposals[label], byId);
    if (line) lines.push(line);
  }

  lines.push('', 'Кандидаты (полное описание):');
  if (!shortlist.length) {
    lines.push('(shortlist пуст)');
  } else {
    shortlist.slice(0, 5).forEach((c, i) => {
      lines.push(...fmtCatBlock(c, i + 1));
    });
  }

  if (suggested) {
    lines.push('', 'Suggested:');
    lines.push(...fmtCatBlock(suggested, '★'));
  }

  let message_text = sanitizeTg(lines.join('\n'));
  if (message_text.length > 3900) {
    message_text = message_text.slice(0, 3899) + '…';
  }

  const approveBtns = [
    { text: '✅ Approve', callback_data: `hr|${qid}|a` },
    { text: '❓ Unresolved', callback_data: `hr|${qid}|u` },
  ];
  const changeRow = [];
  for (const c of shortlist.slice(0, 4)) {
    const cid = Number(c.category_id);
    if (!Number.isFinite(cid)) continue;
    changeRow.push({ text: `→ ${cid}`, callback_data: `hr|${qid}|c|${cid}` });
  }
  changeRow.push({ text: '✏️ Other', callback_data: `hr|${qid}|o` });

  const toN8nRow = (btns) => ({
    row: {
      buttons: btns.map((b) => ({
        text: b.text,
        additionalFields: { callback_data: b.callback_data },
      })),
    },
  });

  const btns = {};
  changeRow.slice(0, 4).forEach((b, i) => {
    btns[`btn${i+1}_text`] = b.text;
    btns[`btn${i+1}_data`] = b.callback_data;
  });
  // pad to 4 so expressions never empty
  for (let i = 1; i <= 4; i++) {
    if (!btns[`btn${i}_text`]) {
      btns[`btn${i}_text`] = '·';
      btns[`btn${i}_data`] = `hr|${qid}|noop`;
    }
  }

  return {
    json: {
      queue_id: qid,
      product_id: payload.product_id,
      telegram_chat_id: chatId,
      message_text,
      reply_markup: { inline_keyboard: [approveBtns, changeRow] },
      n8n_keyboard_rows: [toN8nRow(approveBtns), toN8nRow(changeRow)],
      callback_approve: `hr|${qid}|a`,
      callback_unresolved: `hr|${qid}|u`,
      ...btns,
      skip: !chatId,
      skip_reason: chatId ? null : 'missing_telegram_chat_id',
    },
  };
});

return items.map((item, index) => {
  const prep = $('HR — Format Card').item.json;
  const tg = item.json;
  const result = tg.result || tg;
  const messageId = result.message_id ?? tg.message_id;
  const chatId = result.chat?.id ?? tg.chat?.id ?? prep.telegram_chat_id;
  if (!prep.queue_id) {
    return { json: { ok: false, error: 'missing_queue_id', tg }, pairedItem: index };
  }
  const qid = Number(prep.queue_id);
  const mid = messageId != null ? String(messageId) : '';
  const cid = chatId != null ? String(chatId) : '';
  const query = `
UPDATE classification_review_queue
SET
  status = 'sent_to_telegram',
  sent_at = NOW(),
  telegram_chat_id = COALESCE(NULLIF('${cid.replace(/'/g, "''")}', ''), telegram_chat_id),
  telegram_message_id = COALESCE(NULLIF('${mid.replace(/'/g, "''")}', ''), telegram_message_id)
WHERE id = ${qid}
  AND status IN ('pending', 'sending')
RETURNING id, product_id, status, telegram_message_id, telegram_chat_id;
`;
  return { json: { ...prep, telegram_message_id: mid, query }, pairedItem: index };
});
